const out = [];
const seen = new Set();

const parseMaybeJson = (raw) => {
  if (!raw || typeof raw !== 'string') return null;
  let txt = raw.trim();
  if (!txt) return null;

  txt = txt.replace(/^\uFEFF/, '').trim();
  if (txt.startsWith('```')) {
    txt = txt.replace(/^```json\s*/i, '').replace(/^```/, '').replace(/```$/, '').trim();
  }

  try {
    return JSON.parse(txt);
  } catch (_e) {
    return null;
  }
};

const rowsFromPayload = (payload, fallbackChangeId, fallbackSummary) => {
  const items = [];
  const toText = (v) => String(v || '').trim();
  const cid = Number(fallbackChangeId);

  const pushRow = (changeId, code) => {
    const id = Number(changeId);
    const text = toText(code);
    if (!Number.isFinite(id) || !text) return;
    const key = id + '::' + text;
    if (seen.has(key)) return;
    seen.add(key);
    items.push({ change_id: id, code: text });
  };

  if (Array.isArray(payload)) {
    for (const row of payload) {
      if (row && typeof row === 'object') {
        pushRow(row.change_id ?? cid, row.code ?? row.desc ?? row.description);
      }
    }
  } else if (payload && typeof payload === 'object') {
    if (Array.isArray(payload.rows)) {
      for (const row of payload.rows) {
        if (row && typeof row === 'object') {
          pushRow(row.change_id ?? cid, row.code ?? row.desc ?? row.description);
        }
      }
    }

    if (Array.isArray(payload.code_changes)) {
      for (const code of payload.code_changes) {
        pushRow(cid, code);
      }
    }
  }

  if (items.length === 0 && Number.isFinite(cid)) {
    const fb = toText(fallbackSummary);
    if (fb) pushRow(cid, fb);
  }

  return items;
};

const inputItems = $input.all();
for (let i = 0; i < inputItems.length; i++) {
  const llm = inputItems[i].json || {};
  let src = {};
  try {
    src = $item(i).$node['Build Code Change Rows'].json || {};
  } catch (_e) {
    src = {};
  }

  const raw =
    llm.text ||
    llm.response?.text ||
    llm.response ||
    llm.choices?.[0]?.message?.content ||
    '';

  const parsed = parseMaybeJson(raw);
  const rows = rowsFromPayload(parsed, src.change_id ?? llm.change_id, src.change_summary ?? llm.change_summary);
  for (const row of rows) {
    out.push({ json: row });
  }
}

return out;

const rows = $input.all().map((i) => i.json || {});
if (rows.length === 0) return [];

const changeMeta = new Map();
try {
  const changes = $items('Upsert Change In Repo', 0, 0).map((i) => i.json || {});
  for (const c of changes) {
    const id = Number(c.id);
    if (!Number.isFinite(id)) continue;
    changeMeta.set(id, {
      repo_id: Number(c.repo_id),
      change_summary: String(c.change_summary || '').trim(),
    });
  }
} catch (_e) {}

const repoNamesById = new Map();
try {
  const repos = $items('Load Repos Table', 0, 0).map((i) => i.json || {});
  for (const r of repos) {
    const id = Number(r.id);
    if (Number.isFinite(id)) {
      repoNamesById.set(id, String(r.name || r.repo_name || r.repository || '').trim());
    }
  }
} catch (_e) {}

const grouped = new Map();
for (const row of rows) {
  const changeId = Number(row.change_id);
  const code = String(row.code || '').trim();
  if (!Number.isFinite(changeId) || !code) continue;

  if (!grouped.has(changeId)) {
    const meta = changeMeta.get(changeId) || {};
    const repoId = Number(meta.repo_id);
    grouped.set(changeId, {
      change_id: changeId,
      repo_id: Number.isFinite(repoId) ? repoId : null,
      repo_name: Number.isFinite(repoId) ? (repoNamesById.get(repoId) || '') : '',
      change_summary: String(meta.change_summary || '').trim(),
      code_changes: [],
    });
  }

  grouped.get(changeId).code_changes.push(code);
}

const payload = Array.from(grouped.values());
if (payload.length === 0) return [];

return [{ json: { grouped_changes: payload } }];

