Voce e engenheiro de QA focado em testes unitarios para FastRoute.
Retorne SOMENTE JSON valido (sem markdown) no formato:
{
  "rows": [
    { "change_id": number, "tests": [string] }
  ]
}
Regras:
1) Para cada change_id de entrada, retorne 1 item em rows.
2) tests: 3 a 8 descricoes completas em linguagem natural (pt-BR).
3) Cobrir: caminho feliz, validacoes de regra, erros, edge cases e contrato de retorno.
4) Sem nomes crípticos (ex.: test_x_y), sem texto fora do JSON.

parameters.jsCode:
const input = $input.all();
if (input.length === 0) return [];

let groupedChanges = [];
try {
  groupedChanges = $items('Build Unit Test Prompt Rows', 0, 0)[0]?.json?.grouped_changes || [];
} catch (_e) {}

const fallbackById = new Map();
for (const row of groupedChanges) {
  const id = Number(row.change_id);
  if (Number.isFinite(id)) fallbackById.set(id, row);
}

const parseMaybeJson = (raw) => {
  if (!raw || typeof raw !== 'string') return null;
  let txt = raw.trim();
  if (!txt) return null;
  txt = txt.replace(/^\uFEFF/, '').trim();
  if (txt.startsWith('```')) {
    txt = txt.replace(/^```json\s*/i, '').replace(/^```/, '').replace(/```$/, '').trim();
  }
  try { return JSON.parse(txt); } catch (_e) { return null; }
};

const asTestList = (obj) => {
  if (!obj) return [];
  const src = Array.isArray(obj.tests)
    ? obj.tests
    : Array.isArray(obj.unit_tests)
      ? obj.unit_tests
      : Array.isArray(obj.test_steps)
        ? obj.test_steps
        : [];
  return src.map((t) => String(t || '').trim()).filter(Boolean);
};

const out = [];
const seen = new Set();
const pushRow = (changeId, description) => {
  const cid = Number(changeId);
  const desc = String(description || '').trim();
  if (!Number.isFinite(cid) || !desc) return;
  const key = cid + '::' + desc;
  if (seen.has(key)) return;
  seen.add(key);
  out.push({ json: { change_id: cid, description: desc } });
};

for (const item of input) {
  const llm = item.json || {};
  const raw = llm.text || llm.response?.text || llm.response || llm.choices?.[0]?.message?.content || '';
  const parsed = parseMaybeJson(raw);

  let rows = [];
  if (Array.isArray(parsed)) rows = parsed;
  else if (parsed && typeof parsed === 'object' && Array.isArray(parsed.rows)) rows = parsed.rows;

  if (rows.length === 0) {
    for (const fb of fallbackById.values()) {
      const cid = Number(fb.change_id);
      const base = String(fb.change_summary || '').trim() || 'Change sem resumo';
      const samples = [
        'Validar cenário principal da change ' + cid + ': ' + base + '.',
        'Validar regras de erro e entradas inválidas da change ' + cid + '.',
        'Validar edge cases e consistência de contrato da change ' + cid + '.'
      ];
      for (const s of samples) pushRow(cid, s);
    }
    continue;
  }

  for (const row of rows) {
    const cid = Number(row?.change_id);
    const tests = asTestList(row);
    if (!Number.isFinite(cid)) continue;

    if (tests.length === 0) {
      const fb = fallbackById.get(cid);
      const base = String(fb?.change_summary || '').trim() || ('change ' + cid);
      pushRow(cid, 'Validar cenário principal da ' + base + '.');
      pushRow(cid, 'Validar entradas inválidas e mensagens de erro da ' + base + '.');
      pushRow(cid, 'Validar edge cases e estado final consistente da ' + base + '.');
      continue;
    }

    for (const t of tests) pushRow(cid, t);
  }
}

return out;

const suites = $input.all().map((i) => i.json || {}).filter((r) => r && r.id !== undefined && r.change_id !== undefined);
if (suites.length === 0) return [];

let parsedRows = [];
try {
  parsedRows = $items('Parse Unit Tests JSON', 0, 0).map((i) => i.json || {});
} catch (_e) {}

const byChange = new Map();
for (const row of parsedRows) {
  const cid = Number(row.change_id);
  const desc = String(row.description || '').trim();
  if (!Number.isFinite(cid) || !desc) continue;
  if (!byChange.has(cid)) byChange.set(cid, []);
  byChange.get(cid).push(desc);
}

const out = [];
for (const s of suites) {
  const cid = Number(s.change_id);
  const suiteId = Number(s.id);
  if (!Number.isFinite(cid) || !Number.isFinite(suiteId)) continue;

  const descs = byChange.get(cid) || [];
  const uniq = [...new Set(descs.map((d) => String(d || '').trim()).filter(Boolean))];

  for (const description of uniq) {
    out.push({ json: { testsuite_id: suiteId, description } });
  }
}

return out;

const rows = $items('Normalize', 0, 0).map((i) => i.json || {});
if (rows.length === 0) {
  return [];
}
return rows.map((json) => ({ json }));

parameters.jsonBody:
={{ (() => {
  const analysis = ($json.analysis && typeof $json.analysis === 'object') ? $json.analysis : {};
  const rawSummary = String(analysis.resumo || analysis.summary || 'Sem resumo').trim();
  const safeSummary = rawSummary
    .replace(/["'`]/g, '')
    .replace(/[()]/g, '')
    .replace(/\s+/g, ' ')
    .slice(0, 450);

  const payloadAnalysis = {
    ...analysis,
    resumo: safeSummary,
  };

  return JSON.stringify({
    event_type: 'governance-release',
    client_payload: {
      source_repo: 'fastroute-changemanagement',
      source_ref: 'main',
      domain_ref: $json.domain_ref || 'main',
      api_ref: $json.api_ref || 'main',
      mobile_ref: $json.mobile_ref || 'main',
      mobile_profile: $json.mobile_profile || 'preview',
      run_release: false,
      deploy_api: false,
      auto_implement: true,
      impact_analysis: payloadAnalysis
    }
  });
})() }}
